// Chart.js vendor placeholder.
//
// This file is a STUB that simulates the absence of the real Chart.js UMD
// bundle so the build, the SPA, and the e2e wiring can be exercised without
// network access. When the real bundle is dropped in (see README.md in this
// directory), it overwrites this file and the e2e render test exercises a
// real `new Chart(canvas, ...)` invocation.
//
// The stub exposes a global `Chart` constructor that records what would be
// rendered and emits a console.warn so a developer who forgot to fetch the
// real bundle sees an obvious diagnostic in DevTools. It does NOT render
// anything visible — the placeholder branch of the e2e test runs through
// the loader + /render path only and asserts the *server-produced* config
// JSON, sidestepping the missing renderer entirely.

(function () {
  if (typeof window === 'undefined') return;
  if (window.__topoChartPlaceholder) return;
  window.__topoChartPlaceholder = true;
  function Chart(canvas, config) {
    this.canvas = canvas;
    this.config = config;
    if (typeof console !== 'undefined' && console.warn) {
      console.warn(
        '[topo-debug] chart.umd.min.js is a placeholder. Drop the real ' +
        'Chart.js UMD bundle at topo-core/lib/Debug/Server/vendor/chart.umd.min.js ' +
        'to enable real chart rendering. See README.md in the same directory.'
      );
    }
  }
  Chart.prototype.update = function () {};
  Chart.prototype.destroy = function () {};
  window.Chart = Chart;
})();
